198	export async function createSessionWithCdp(
199	  headers: Record<string, string>,
200	): Promise<SessionInfo> {
201	  const url = getBaseUrl();
202	  const startPayload = {
203	    modelName: "gpt-4.1-nano",
204	    ...createLocalBrowserBody(),
205	  };
206	
207	  let lastError: Error | undefined;
208	  for (let attempt = 1; attempt <= SESSION_START_MAX_ATTEMPTS; attempt += 1) {
209	    const response = await fetch(`${url}/v1/sessions/start`, {
210	      method: "POST",
211	      headers,
212	      body: JSON.stringify(startPayload),
213	    });
214	
215	    const responseText = await response.text();
216	    let parsedBody: unknown;
217	    try {
218	      parsedBody = responseText ? JSON.parse(responseText) : null;
219	    } catch {
220	      parsedBody = responseText;
221	    }
222	    const body = parsedBody as StartSessionResponse;
223	
224	    if (response.ok && body?.success) {
225	      if (!body.data?.available) {
226	        throw new Error("Session not available");
227	      }
228	      if (!body.data.sessionId) {
229	        throw new Error("No sessionId returned");
230	      }
231	      if (!body.data.cdpUrl) {
232	        throw new Error("No cdpUrl returned");
233	      }
234	
235	      // Wait for session to be fully ready before returning
236	      await sleep(SESSION_READY_DELAY_MS);
237	
238	      return {
239	        sessionId: body.data.sessionId,
240	        cdpUrl: body.data.cdpUrl,
241	      };
242	    }
243	
244	    lastError = new Error(
245	      `Failed to create session (status=${response.status}): ${JSON.stringify(
246	        parsedBody,
247	      )}\n${readLaunchDiagnostics(startPayload.browser?.launchOptions)}`,
248	    );
249	
250	    const shouldRetry =
251	      response.status === HTTP_INTERNAL_SERVER_ERROR &&
252	      attempt < SESSION_START_MAX_ATTEMPTS;
253	    if (!shouldRetry) {
254	      throw lastError;
255	    }
256	
257	    await sleep(SESSION_START_RETRY_DELAY_MS * attempt);
258	  }
259	
260	  throw lastError ?? new Error("Failed to create session");
261	}
