332	export async function readSSEStream(response: Response): Promise<SSEEvent[]> {
333	  const reader = response.body?.getReader() as
334	    | ReadableStreamDefaultReader<Uint8Array>
335	    | undefined;
336	  if (!reader) {
337	    throw new Error("No response body reader available");
338	  }
339	
340	  const decoder = new TextDecoder();
341	  let fullResponse = "";
342	
343	  for (;;) {
344	    const result = await reader.read();
345	    if (result.done) break;
346	    fullResponse += decoder.decode(result.value, { stream: true });
347	  }
348	
349	  // Parse SSE events
350	  const events: SSEEvent[] = [];
351	  const rawEvents = fullResponse.split("\n\n").filter((e) => e.trim());
352	
353	  for (const rawEvent of rawEvents) {
354	    const event: SSEEvent = {};
355	    const lines = rawEvent.split("\n");
356	
357	    for (const line of lines) {
358	      if (line.startsWith("event:")) {
359	        event.event = line.slice(6).trim();
360	      } else if (line.startsWith("data:")) {
361	        event.data = line.slice(5).trim();
362	        try {
363	          event.parsed = JSON.parse(event.data);
364	        } catch {
365	          // Keep as string if not valid JSON
366	        }
367	      }
368	    }
369	
370	    if (event.data || event.event) {
371	      events.push(event);
372	    }
373	  }
374	
375	  return events;
376	}
