400	  const reader = response.body?.getReader() as
401	    | ReadableStreamDefaultReader<Uint8Array>
402	    | undefined;
403	  if (!reader) throw new Error("No response body reader");
404	
405	  const decoder = new TextDecoder();
406	  let fullResponse = "";
407	
408	  for (;;) {
409	    const result = await reader.read();
410	    if (result.done) break;
411	    fullResponse += decoder.decode(result.value, { stream: true });
412	  }
