417	/**
418	 * Parse raw SSE response string into typed events
419	 */
420	export function parseTypedSSEEvents<TResult = unknown>(
421	  rawResponse: string,
422	): TypedSSEEvent<TResult>[] {
423	  const events = rawResponse.split("\n\n").filter((e) => e.trim());
424	  return events
425	    .map((event) => {
426	      const dataMatch = event.match(/data: (.+)/);
427	      if (dataMatch?.[1]) {
428	        return JSON.parse(dataMatch[1]) as TypedSSEEvent<TResult>;
429	      }
430	      return null;
431	    })
432	    .filter((e): e is TypedSSEEvent<TResult> => e !== null);
433	}
