101	async function getFreePort(): Promise<number> {
102	  return await new Promise((resolve, reject) => {
103	    const server = net.createServer();
104	    server.listen(0, "127.0.0.1", () => {
105	      const addr = server.address();
106	      if (!addr || typeof addr === "string") {
107	        reject(new Error("Failed to allocate an ephemeral port"));
108	        return;
109	      }
110	      const { port } = addr;
111	      server.close((error) => {
112	        if (error) {
113	          reject(error);
114	          return;
115	        }
116	        resolve(port);
117	      });
118	    });
119	    server.on("error", reject);
120	  });
121	}
122	
123	function listProcesses(): Array<{ pid: number; args: string }> {
124	  const output = execFileSync("ps", ["-axo", "pid=,args="], {
125	    encoding: "utf8",
126	  });
127	  return output
128	    .split("\n")
129	    .map((line) => line.trim())
130	    .filter(Boolean)
131	    .map((line) => {
132	      const firstSpace = line.indexOf(" ");
133	      if (firstSpace === -1) {
134	        return { pid: Number(line), args: "" };
135	      }
136	      return {
137	        pid: Number(line.slice(0, firstSpace)),
138	        args: line.slice(firstSpace + 1),
139	      };
140	    })
141	    .filter((entry) => Number.isFinite(entry.pid) && entry.pid > 0);
142	}
143	
144	function parseSupervisorConfigArg(args: string): {
145	  kind?: string;
146	  pid?: number;
147	  parentPid?: number;
148	} | null {
149	  const prefix = "--supervisor-config=";
150	  const index = args.indexOf(prefix);
151	  if (index === -1) return null;
152	  const raw = args.slice(index + prefix.length).trim();
153	  if (!raw) return null;
154	  try {
155	    return JSON.parse(raw) as {
156	      kind?: string;
157	      pid?: number;
158	      parentPid?: number;
159	    };
160	  } catch {
161	    return null;
162	  }
163	}
164	
165	function findLocalSupervisorByParentPid(
166	  parentPid: number,
167	): SupervisorInfo | null {
168	  const candidates = listProcesses()
169	    .map((entry) => ({
170	      ...entry,
171	      config: parseSupervisorConfigArg(entry.args),
172	    }))
173	    .filter(
174	      (entry) =>
175	        entry.config?.kind === "LOCAL" && entry.config.parentPid === parentPid,
176	    )
177	    .sort((a, b) => b.pid - a.pid);
178	
179	  const entry = candidates[0];
180	  if (!entry) return null;
181	
182	  return {
183	    pid: entry.pid,
184	    args: entry.args,
185	    chromePid:
186	      typeof entry.config?.pid === "number" && Number.isFinite(entry.config.pid)
187	        ? entry.config.pid
188	        : undefined,
189	  };
190	}
191	
192	function isPidAlive(pid: number): boolean {
193	  try {
194	    process.kill(pid, 0);
195	    return true;
196	  } catch (error) {
197	    const err = error as NodeJS.ErrnoException;
198	    if (err.code === "ESRCH") return false;
199	    return true;
200	  }
201	}
202	
203	async function waitForValue<T>(
204	  read: () => T | null,
205	  timeoutMs: number,
206	  intervalMs = 200,
207	): Promise<T> {
208	  const startedAt = Date.now();
209	  while (Date.now() - startedAt < timeoutMs) {
210	    const value = read();
211	    if (value !== null) return value;
212	    await sleep(intervalMs);
213	  }
214	  throw new Error(`Timed out after ${timeoutMs}ms`);
215	}
216	
217	async function waitForPidState(
218	  pid: number,
219	  shouldBeAlive: boolean,
220	  timeoutMs: number,
221	): Promise<void> {
222	  const startedAt = Date.now();
223	  while (Date.now() - startedAt < timeoutMs) {
224	    if (isPidAlive(pid) === shouldBeAlive) return;
225	    await sleep(200);
226	  }
227	  const entry = listProcesses().find((candidate) => candidate.pid === pid);
228	  const details = entry ? ` args=${entry.args}` : "";
229	  throw new Error(
230	    `PID ${pid} did not become ${shouldBeAlive ? "alive" : "dead"} within ${timeoutMs}ms${details}`,
231	  );
232	}
