234	async function waitForServerReady(baseUrl: string, timeoutMs = 30_000) {
235	  const startedAt = Date.now();
236	  while (Date.now() - startedAt < timeoutMs) {
237	    try {
238	      const response = await fetch(`${baseUrl}/healthz`);
239	      if (response.ok) return;
240	    } catch {
241	      // retry
242	    }
243	    await sleep(500);
244	  }
245	  throw new Error(
246	    `Server did not become ready at ${baseUrl} within ${timeoutMs}ms`,
247	  );
248	}
249	
250	async function waitForProcessExit(
251	  proc: ChildProcessWithoutNullStreams,
252	  timeoutMs: number,
253	): Promise<boolean> {
254	  if (proc.exitCode !== null) {
255	    return true;
256	  }
257	  return await new Promise((resolve) => {
258	    const timer = setTimeout(() => resolve(false), timeoutMs);
259	    proc.once("exit", () => {
260	      clearTimeout(timer);
261	      resolve(true);
262	    });
263	  });
264	}
