266	async function startSeaServer(
267	  envOverrides: Record<string, string> = {},
268	): Promise<SeaHandle> {
269	  const port = await getFreePort();
270	  const baseUrl = `http://127.0.0.1:${port}`;
271	  const logs: string[] = [];
272	  const proc = spawn(
273	    seaBinaryPath,
274	    ["--node-options=--no-lazy --enable-source-maps"],
275	    {
276	      env: {
277	        ...process.env,
278	        ...envOverrides,
279	        NODE_ENV: "production",
280	        PORT: String(port),
281	        STAGEHAND_SEA_CACHE_DIR:
282	          process.env.STAGEHAND_SEA_CACHE_DIR ?? `${repoRoot}/.stagehand-sea`,
283	      },
284	      stdio: ["ignore", "pipe", "pipe"],
285	    },
286	  );
287	
288	  proc.stdout.on("data", (chunk: Buffer) => {
289	    const value = chunk.toString().trim();
290	    if (value) logs.push(value);
291	  });
292	  proc.stderr.on("data", (chunk: Buffer) => {
293	    const value = chunk.toString().trim();
294	    if (value) logs.push(value);
295	  });
296	
297	  if (!proc.pid) {
298	    throw new Error("SEA process did not provide a PID");
299	  }
300	
301	  const handle: SeaHandle = { proc, baseUrl, logs };
302	  activeSea.add(handle);
303	
304	  try {
305	    await waitForServerReady(baseUrl);
306	    return handle;
307	  } catch (error) {
308	    await stopSeaServer(handle);
309	    const tail = logs.slice(-30).join("\n");
310	    throw new Error(
311	      `Failed to start SEA server at ${baseUrl}: ${(error as Error).message}\n${tail}`,
312	      {
313	        cause: error,
314	      },
315	    );
316	  }
317	}
