319	async function stopSeaServer(handle: SeaHandle): Promise<void> {
320	  const { proc } = handle;
321	  if (proc.exitCode !== null) return;
322	  try {
323	    proc.kill("SIGTERM");
324	  } catch {
325	    // ignore
326	  }
327	  const exited = await waitForProcessExit(proc, 5_000);
328	  if (!exited) {
329	    try {
330	      proc.kill("SIGKILL");
331	    } catch {
332	      // ignore
333	    }
334	    await waitForProcessExit(proc, 5_000);
335	  }
336	}
