439	async function closeLocalBrowserViaCdp(cdpUrl: string): Promise<void> {
440	  const browser = await chromium.connectOverCDP(cdpUrl);
441	  try {
442	    const context = browser.contexts()[0];
443	    if (!context) return;
444	    const page = context.pages()[0] ?? (await context.newPage());
445	    const cdp = await context.newCDPSession(page);
446	    await cdp.send("Browser.close");
447	  } finally {
448	    await browser.close().catch(() => {
449	      // best-effort close of Playwright transport
450	    });
451	  }
452	}
