454	async function waitForBrowserbaseNotRunning(
455	  sessionId: string,
456	  timeoutMs: number,
457	): Promise<string> {
458	  assert.ok(bbApiKey, "BROWSERBASE_API_KEY must be set");
459	  const bb = new Browserbase({ apiKey: bbApiKey });
460	
461	  let lastStatus = "UNKNOWN";
462	  const startedAt = Date.now();
463	  while (Date.now() - startedAt < timeoutMs) {
464	    try {
465	      const snapshot = (await bb.sessions.retrieve(sessionId)) as {
466	        status?: string;
467	      };
468	      lastStatus = snapshot.status ?? "UNKNOWN";
469	      if (lastStatus !== "RUNNING") {
470	        return lastStatus;
471	      }
472	    } catch {
473	      return "RETRIEVE_FAILED";
474	    }
475	    await sleep(1000);
476	  }
