      isPidAlive(supervisor.pid),
      `Supervisor PID ${supervisor.pid} should be alive`,
    );
    assert.ok(
      isPidAlive(supervisor.chromePid),
      `Chrome PID ${supervisor.chromePid} should be alive`,
